class Solution {
public:
    int minimizeXor(int num1, int num2) {
        int k = __builtin_popcount(num2);
        int m = __builtin_popcount(num1);
        if (m == k) {
            return num1;
        }
        int x = num1;
        if (m < k) {
            int needed = k - m;
            for (int i = 0; i < 31; ++i) {
                if ((num1 & (1 << i)) == 0) {
                    x |= (1 << i);
                    needed--;
                    if (needed == 0) {
                        break;
                    }
                }
            }
        } else {
            int needed = m - k;
            for (int i = 0; i < 31; ++i) {
                if ((num1 & (1 << i)) != 0) {
                    x &= ~(1 << i);
                    needed--;
                    if (needed == 0) {
                        break;
                    }
                }
            }
        }
        return x;
    }
};

